impl.spec_text:
    use vstd::prelude::*;

    #[verifier::prophetic]
    spec fn f() -> int {
        5
    }

    spec fn test() -> int {
        let g = f; // may be supported in the future, meaning the same as "let g = || f();"
        g() // returning g() should fail, because the result of calling g() is a prophetic int, not an unrestricted int
    }
